import sys
import threading
from collections import deque, defaultdict

def main():
    import sys
    input = sys.stdin.read
    data = input().split()

    idx = 0
    N = int(data[idx])
    idx += 1
    M = int(data[idx])
    idx += 1

    sets = []
    for _ in range(N):
        A_i = int(data[idx])
        idx += 1
        elements = list(map(int, data[idx:idx+A_i]))
        idx += A_i
        sets.append(set(elements))

    # Build adjacency list
    adj = [[] for _ in range(N)]
    element_to_sets = defaultdict(list)

    for i in range(N):
        for elem in sets[i]:
            element_to_sets[elem].append(i)

    for i in range(N):
        for elem in sets[i]:
            for j in element_to_sets[elem]:
                if i < j:
                    adj[i].append(j)
                    adj[j].append(i)

    # BFS setup
    start_nodes = []
    end_nodes = []
    for i in range(N):
        if 1 in sets[i]:
            start_nodes.append(i)
        if M in sets[i]:
            end_nodes.append(i)

    if not start_nodes or not end_nodes:
        print(-1)
        return

    # BFS from all start nodes
    visited = [-1] * N
    q = deque()
    for node in start_nodes:
        visited[node] = 0
        q.append(node)

    while q:
        u = q.popleft()
        for v in adj[u]:
            if visited[v] == -1:
                visited[v] = visited[u] + 1
                q.append(v)

    min_ops = -1
    for node in end_nodes:
        if visited[node] != -1:
            if min_ops == -1 or visited[node] < min_ops:
                min_ops = visited[node]

    print(min_ops)

threading.Thread(target=main).start()
